INSERT INTO recipe_items (menu_item_id, ingredient_id, quantity) SELECT m.id, i.id, 0.15 FROM menu_items m JOIN menu_categories c ON m.category_id = c.id, ingredients i WHERE m.name = 'Жаровня из Семги' AND c.name = '2 Блюда' AND i.name ILIKE '%Семга%' LIMIT 1;
